function parseStrictJson(raw) {
  const source = typeof raw === 'string'
    ? raw
    : raw?.text ?? raw?.output ?? raw?.result ?? JSON.stringify(raw);

  const text = String(source || '').trim();
  if (!text) throw new Error('Parser: empty LLM output.');

  const candidates = [
    text,
    text.replace(/```json\s*/gi, '').replace(/```/g, '').trim()
  ];

  for (const candidate of candidates) {
    try {
      return JSON.parse(candidate);
    } catch {}
  }

  const stripped = candidates[1];
  const start = stripped.indexOf('{');
  const end = stripped.lastIndexOf('}');
  if (start >= 0 && end > start) {
    const slice = stripped.slice(start, end + 1)
      .replace(/[\u201C\u201D]/g, '"')
      .replace(/[\u2018\u2019]/g, "'")
      .replace(/,\s*}/g, '}')
      .replace(/,\s*]/g, ']');

    try {
      return JSON.parse(slice);
    } catch (err) {
      throw new Error(`Parser: invalid salvaged JSON. ${err.message}`);
    }
  }

  throw new Error('Parser: could not find a valid JSON object.');
}

const BASE_NODE = 'Assemble Parent Packet';
const OUT_KEY = 'series_plan';

const base = $items(BASE_NODE)[0]?.json;
if (!base) {
  throw new Error(`Parser: base node "${BASE_NODE}" returned no data.`);
}

const parsed = parseStrictJson($json);

// Per-output hardening
if (OUT_KEY === 'critic') {
  parsed.approve = Boolean(parsed.approve);
  for (const key of ['score', 'brand_fit', 'novelty', 'visual_viability']) {
    parsed[key] = Number(parsed[key] || 0);
  }
}

if (OUT_KEY === 'abstraction') {
  let a = Number(parsed.abstraction_target || 6.2);
  const min = Number(base.ctx?.target_abstraction_min || 5.8);
  const max = Number(base.ctx?.target_abstraction_max || 6.8);
  if (!Number.isFinite(a)) a = 6.2;
  a = Math.max(min, Math.min(max, a));
  parsed.abstraction_target = Math.round(a * 10) / 10;
}

if (OUT_KEY === 'render_spec') {
  parsed.image_size = String(parsed.image_size || base.ctx?.image_size || '1024x1280');
  parsed.provider_controls = (parsed.provider_controls && typeof parsed.provider_controls === 'object')
    ? parsed.provider_controls
    : {};
  parsed.provider_controls.quality = String(parsed.provider_controls.quality || base.ctx?.quality || 'high');
  parsed.provider_controls.background = String(parsed.provider_controls.background || base.ctx?.background || 'opaque');
  parsed.provider_controls.output_format = String(parsed.provider_controls.output_format || base.ctx?.output_format || 'png');
}

if (OUT_KEY === 'caption_pack') {
  parsed.hashtags = Array.isArray(parsed.hashtags) ? parsed.hashtags : [];
  parsed.keywords = Array.isArray(parsed.keywords) ? parsed.keywords : [];
}

if (OUT_KEY === 'series_plan') {
  parsed.variations = Array.isArray(parsed.variations) ? parsed.variations : [];
}

return [{
  json: {
    ...base,
    [OUT_KEY]: parsed
  }
}];

function fnv1a(str) {
  let h = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    h ^= str.charCodeAt(i);
    h = (h >>> 0) * 0x01000193;
  }
  return (h >>> 0).toString(16);
}

const j = $json || {};
const ctx = j.ctx || {};
const parentConcept = j.parent?.concept || {};
const parentAsset = j.parent?.asset || {};
const plan = j.series_plan || {};

const rootId = String(parentConcept.root_concept_id || parentConcept.concept_id || '').trim();
const parentId = String(parentConcept.concept_id || '').trim();
const rootAssetId = String(parentAsset.root_asset_id || parentAsset.asset_id || '').trim();
const parentAssetId = String(parentAsset.asset_id || '').trim();

if (!parentId) throw new Error('TVPX__50: missing parent concept_id.');
if (!parentAssetId) throw new Error('TVPX__50: missing parent asset_id.');

const now = new Date().toISOString();
const variations = Array.isArray(plan.variations) ? plan.variations : [];

return variations.map((v) => {
  const delta = String(v.prompt_delta || v.variation_instruction || '').trim();
  const seed = `${ctx.trace_id}::${parentId}::${v.variation_index}::${delta}`;
  const childId = `tvpx_cp_${fnv1a(seed)}`;

  let seriesDNA = {};
  try {
    seriesDNA = JSON.parse(String(parentConcept.series_dna_json || '{}'));
  } catch {
    seriesDNA = {};
  }

  const seriesGroupId = String(
    plan.series_group_id ||
    seriesDNA.series_group_id ||
    `tvpx_series_${fnv1a(parentId + '::' + now)}`
  ).trim();

  const childSeriesDNA = {
    ...seriesDNA,
    series_group_id: seriesGroupId,
    variation_index: Number(v.variation_index || 0),
    prompt_delta: delta,
    palette_shift: String(v.palette_shift || '').trim(),
    atmosphere_shift: String(v.atmosphere_shift || '').trim(),
    intensity_change: String(v.intensity_change || '').trim()
  };

  const thesis = String(parentConcept.concept_thesis || '').trim();
  const variationInstruction = String(v.variation_instruction || '').trim();
  const childThesis = variationInstruction
    ? `${thesis} | Variation: ${variationInstruction}`
    : thesis;

  return {
    json: {
      ctx,
      child: {
        concept_id: childId,
        trace_id: ctx.trace_id,
        origin_type: 'telegram_series',
        source_id: String(parentConcept.source_id || '').trim(),
        parent_concept_id: parentId,
        root_concept_id: rootId,
        seed_fragment_ids_json: String(parentConcept.seed_fragment_ids_json || '[]'),
        concept_thesis: childThesis,
        symbolic_tension: String(parentConcept.symbolic_tension || '').trim(),
        material_anchor: String(parentConcept.material_anchor || '').trim(),
        spatial_directive: String(parentConcept.spatial_directive || '').trim(),
        palette_directive: String(parentConcept.palette_directive || '{}'),
        texture_directive: String(parentConcept.texture_directive || '{}'),
        abstraction_target: Number(parentConcept.abstraction_target || 6.2),
        series_dna_json: JSON.stringify(childSeriesDNA),
        prompt_guardrails_json: String(parentConcept.prompt_guardrails_json || '{}'),
        quality_score: Number(parentConcept.quality_score || 0),
        state: 'ready',
        lock_owner: '',
        lock_expires_at: null,
        used_count: 0,
        last_used_at: null,
        created_at: now,
        updated_at: now
      },
      lineage: {
        lineage_id: `tvpx_lin_${fnv1a(childId + '::' + parentId)}`,
        series_group_id: seriesGroupId,
        root_asset_id: rootAssetId,
        parent_asset_id: parentAssetId,
        child_asset_id: null,
        parent_concept_id: parentId,
        child_concept_id: childId,
        variation_index: Number(v.variation_index || 0),
        variation_instruction: variationInstruction,
        continuity_rules_json: JSON.stringify(plan.continuity_rules || {}),
        created_at: now
      }
    }
  };
});
